import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define a maximum buffer size to prevent buffer overflow
        int maxBufferSize = 10;

        char[] buffer = new char[maxBufferSize];

        // Truncate user input if it exceeds the buffer size
        userInput.getChars(0, Math.min(userInput.length(), maxBufferSize), buffer, 0);

        // Loop through only up to the actual length of the input in the buffer
        for (int i = 0; i < Math.min(userInput.length(), maxBufferSize); i++) {
            System.out.println(buffer[i]);
        }

        scanner.close();
    }
}

### Explanation:
